import React from 'react';
import { Formik, Form, Field, ErrorMessage } from 'formik'; //for form
import * as Yup from 'yup'; //for validation
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Registration() {

    let navigate = useNavigate();

    const initialValues = {
        username: "",
        password: "",
    };

    const validationSchema = Yup.object().shape({
        username: Yup.string().min(3).max(16).required(),
        password: Yup.string().min(4).max(20).required(),
    });

    const onSubmit = (data) => {
        axios.post('http://localhost:3001/auth', data).then(async (response) => {
            // console.log(response, "data added to database");
            navigate('/'); //comeback to main page
        });
    };

  return (
    <div className='addUserPage'>
        <Formik 
            initialValues={initialValues} 
            onSubmit={onSubmit} 
            validationSchema={validationSchema} 
        >
            <Form className='formContainer'>
                <label className='formLabel'>User name:</label>
                <ErrorMessage name='username' component="span" />
                <Field 
                    id="inputCreateUsername" 
                    name="username" 
                    placeholder="Enter your name" 
                    autoComplete="off"
                />
                <label className='formLabel'>User password:</label>
                <ErrorMessage name='password' component="span" />
                <Field 
                    id="inputCreatePassword" 
                    type="password"
                    name="password" 
                    placeholder="Enter your password" 
                    autoComplete="off"
                />
                <button type='submit'>Register</button>
            </Form> 
        </Formik>
    </div>
  )
}

export default Registration
